+            .simulated_data
+            .alerts
+            .iter()
+            .rev()
+            .take(max_items)
+            .collect();
+
+        for (i, alert) in alerts.iter().enumerate() {
+            if i as u16 >= inner.height {
+                break;
+            }
+
+            let y = inner.y + i as u16;
+
+            // Severity indicator and color
